            List reportees = new ArrayList();
            String accountExpire = "accountExpires";
            String adExpAttrName  = "accountExpires";
          
	

            
			  	  if (form != void && null != form.getField("ctrExpDt") && null != form.getField("ctrExpDt").getValue()  &&
            form.getField("ctrExpDt").getValue().equalsIgnoreCase("Select All Active Contractors")) {
            String identityName=null;            
            List ids = new ArrayList(); 
            Identity identity=null;
            QueryOptions query = null;
            String isContractor=null;
            String idName=null;
            String UserName = null;
            String strContractorStatus=null;

            try{        
            UserName = contractorSupervisor;
            if(UserName!=null){

            query = new QueryOptions();
            identity= context.getObjectByName(Identity.class,UserName);                

            Filter myFilter = Filter.eq("manager", identity);
            query.addFilter(myFilter);
            ids = context.getObjects(Identity.class,query);           
            }             
            for(Identity reportee : ids){
            List idAttribList = new ArrayList();
            isContractor=reportee.getStringAttribute("type");
             strContractorStatus=(reportee.isInactive().toString()==null)?"false":reportee.isInactive().toString();
              if(isContractor !=null && isContractor.equalsIgnoreCase("contractor") && strContractorStatus.equalsIgnoreCase("false") && !isAssignEndDatePopulated(reportee) ){
							idAttribList.add(reportee.getName());
              String emailAddr = reportee.getAttribute("email") != null ? reportee.getAttribute("email").toString() : "No Email";
              String displayVal = reportee.getName()+" :"+reportee.getDisplayableName() + " ( Email: " + emailAddr + ")";
              idAttribList.add(displayVal);
              reportees.add(idAttribList);

              }
            }

            return reportees;


            }catch(Exception e){
							
            	throw e;
            }   

            }else if (form != void && null != form.getField("ctrExpDt") && null != form.getField("ctrExpDt").getValue()  && 
            !form.getField("ctrExpDt").getValue().equalsIgnoreCase("Select Expiration Days")) {
            try{
                int rDays  =Integer.parseInt(form.getField("ctrExpDt").getValue()) ;		
                log.trace("RAJESH CWR..:"+rDays);
                 ExtendCWRExpiration ecw = new ExtendCWRExpiration("error");
             		String types = "contractor,non-hr contractor";
                reportees = ecw.getFilteredADLinksForManager(contractorSupervisor,rDays,types);
                log.trace("RAJESH REPORTEES..:"+contractorSupervisor);
            }catch(Exception e){
              log.trace("ERRORS: Error loading users: "+e,e);
              throw new RuntimeException("ERRORS: Error loading users: "+e,e);
            }
            
            		
           }else if (reportees.size() == 0 || reportees.isEmpty()) {
		            reportees.add("No contractors available");
		        }
            return reportees;

